// Backward-compat alias

export const STOCK_ITEMS = stockItems;

// Map orifice → nozzle code
export const NOZZLE_BY_ORIFICE: Record<number, string> = {
  0.15: 'NOR NMC15SS303C-AD',
  0.20: 'NOR NMC20SS303C-AD',
  0.25: 'NOR NMC25S303C-AD',
  0.30: 'NOR NMC30SS303C-AD',
};

// Nozzle flow rates by orifice at typical pressure (ml/h)
export const NOZZLE_FLOW_BY_ORIFICE: Record<number, number> = {
  0.15: 30600,
  0.20: 54000,
  0.25: 84600,
  0.30: 122400,
};

export function getStockItem(code: string): StockItem | undefined {
  return STOCK_ITEMS.find(i => i.code === code);
}

export function getStockPrice(code: string): number {
  const resolved = migrateStockCode(code);
  return STOCK_ITEMS.find(i => i.code === resolved)?.price ?? 0;
}

export function getStockNameEn(code: string): string {
  const canonical = LEGACY_CODE_MAP[code] ?? code;
  return (
    STOCK_ITEMS.find(s => s.code === canonical)?.nameEn ??
    STOCK_ITEMS.find(s => s.code === code)?.nameEn ??
    code
  );
}

export function getPipe10mmForSpacing(spacingCm: number): { code: string; name: string; price: number } {
  const codes: Record<string, string> = {
    '200': 'NOR 0311016', '250': 'NOR 0311017', '300': 'NOR 0311018',
  };
  const c = spacingCm <= 200 ? 'NOR 0311016'
    : spacingCm <= 250 ? 'NOR 0311017'
    : spacingCm <= 300 ? 'NOR 0311018'
    : 'NOR 0311019';
  return { code: c, name: getStockNameEn(c), price: getStockPrice(c) };
}
